#include <stdio.h>
#include <string.h>

typedef struct column_
{
	int c[3];
}column_t;

typedef struct matrix_
{
	column_t r[3];
}matrix_t;

typedef struct grid_
{
	matrix_t mx;
}grid_t;

int judge(grid_t *h, int num)
{
	int i = 0;
	for (i = 0; i < 3; ++i)
	{
		if ((num == h->mx.r[i].c[0]) && (num == h->mx.r[i].c[1]) && (num == h->mx.r[i].c[2]))
		{
			return 1;
		}
	}

	for (i = 0; i < 3; ++i)
	{
		if ((num == h->mx.r[0].c[i]) && (num == h->mx.r[1].c[i]) && (num == h->mx.r[2].c[i]))
		{
			return 1;
		}
	}

	if ((num == h->mx.r[0].c[0]) && (num == h->mx.r[1].c[1]) && (num == h->mx.r[2].c[2]))
	{
		return 1;
	}

	if ((num == h->mx.r[0].c[2]) && (num == h->mx.r[1].c[1]) && (num == h->mx.r[2].c[0]))
	{
		return 1;
	}

	return 0;
}

int main()
{
	grid_t t;
	char st[4] = { 0 };
	int tot_1 = 0;
	int tot_2 = 0;
	int win_1 = 0;
	int win_2 = 0;

	int i = 0;
	int j = 0;

	for (i = 0; i < 3; ++i)
	{
		scanf("%s", st);
		for (j = 0; j < 3; ++j)
		{
			switch (st[j])
			{
			case 'X':
				t.mx.r[i].c[j] = 1;
				++tot_1;
				break;
			case '0':
				t.mx.r[i].c[j] = 2;
				++tot_2;
				break;
			case '.':
				t.mx.r[i].c[j] = 0;
				break;
			default:
				break;
			}
		}
	}

	if ((tot_1 - tot_2 < 0) || (tot_1 - tot_2 > 1))
	{
		printf("illegal");
		return 0;
	}

	win_1 = judge(&t, 1);
	win_2 = judge(&t, 2);

	if ((0 == win_1) && (0 == win_2))
	{
		if ((5 == tot_1) && (4 == tot_2))
		{
			printf("draw");
			return 0;
		}

		if (tot_1 > tot_2)
		{
			printf("second");
			return 0;
		}
		printf("first");
		return 0;
	}

	if ((1 == win_1) && (0 == win_2) && (tot_1 > tot_2))
	{
		printf("the first player won");
		return 0;
	}

	if ((0 == win_1) && (1 == win_2) && (tot_1 == tot_2))
	{
		printf("the second player won");
		return 0;
	}

	printf("illegal");
	return 0;
}

