macro_rules! parse_line {
    ($t: ty) => ({
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        let a_str = a_str.trim();
        a_str.parse::<$t>().expect("parse error")
    });
    ($($t: ty),+) => ({
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        let mut a_iter = a_str.split_whitespace();
        (
            $(
            a_iter.next().unwrap().parse::<$t>().expect("parse error"),
            )+
        )
    })
}

macro_rules! parse_line_to_vec {
    ($t: ty) => {{
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        (a_str
            .split_whitespace()
            .map(|x| x.parse::<$t>().unwrap())
            .collect::<Vec<$t>>())
    }};
}

fn solve() {
    let field = [
        parse_line!(String).bytes().collect::<Vec<_>>(),
        parse_line!(String).bytes().collect::<Vec<_>>(),
        parse_line!(String).bytes().collect::<Vec<_>>(),
    ];
    let mut xs = 0;
    let mut os = 0;
    for i in 0..3 {
        for j in 0..3 {
            if field[i][j] == b'X' {
                xs += 1;
            }
            if field[i][j] == b'0' {
                os += 1;
            }
        }
    }
    let ok = xs == os || xs == os + 1;
    if !ok {
        return println!("illegal");
    }
    let mut xts = false;
    let mut ots = false;
    for i in 0..3 {
        let mut xcol = true;
        let mut xrow = true;
        let mut ocol = true;
        let mut orow = true;
        for j in 0..3 {
            xcol &= field[j][i] == b'X';
            xrow &= field[i][j] == b'X';
            ocol &= field[j][i] == b'0';
            orow &= field[i][j] == b'0';
        }
        xts |= xcol | xrow;
        ots |= ocol | orow;
    }
    let mut xd1 = true;
    let mut xd2 = true;
    let mut od1 = true;
    let mut od2 = true;
    for i in 0..3 {
        xd1 &= field[i][i] == b'X';
        xd2 &= field[i][2 - i] == b'X';
        od1 &= field[i][i] == b'0';
        od2 &= field[i][2 - i] == b'0';
    }
    xts |= xd1 | xd2;
    ots |= od1 | od2;
    if xts && ots {
        return println!("illegal");
    }
    if xts {
        if xs == os {
            return println!("illegal")
        }
        return println!("the first player won");
    }
    if ots {
        if xs != os {
            return println!("illegal")
        }
        return println!("the second player won");
    }
    if xs + os == 9 {
        return println!("draw");
    }
    if xs == os {
        return println!("first");
    }
    println!("second");
}

fn main() {
    let tests = 1; // parse_line!(usize);
    for _ in 0..tests {
        solve();
    }
}
